import React from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface ProgressData {
  examsPassed: number;
  totalExams: number;
  studyHours: number;
  targetDate: string;
}

interface Exam {
  name: string;
  status: string;
}

interface StudyHoursPerWeek {
  week: string;
  hours: number;
}

interface WidgetData {
  progress: ProgressData;
  exams: Exam[];
  studyHoursPerWeek: StudyHoursPerWeek[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { progress, exams, studyHoursPerWeek } = data;
  const progressPercentage = (progress.examsPassed / progress.totalExams) * 100;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#4A90E2', mb: 1 }}>
              Certification Progress
            </Typography>
            <Typography variant="body1" color="text.secondary">
              {progress.examsPassed} of {progress.totalExams} exams passed
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#4A90E2' }}>
                {progressPercentage.toFixed(0)}%
              </Typography>
            </Stack>
            <CircularProgress
              variant="determinate"
              value={progressPercentage}
              sx={{
                color: '#4A90E2',
                '& svg': {
                  width: 40,
                  height: 40,
                },
              }}
            />
          </Box>

          <Box>
            <Typography variant="h6" sx={{ color: '#4A90E2', mb: 1 }}>
              Study Hours per Week
            </Typography>
            <BarChart
              height={140}
              series={[
                {
                  data: studyHoursPerWeek.map(d => d.hours),
                  color: '#4A90E2',
                },
              ]}
              xAxis={[
                {
                  data: studyHoursPerWeek.map(d => d.week),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
